param([Parameter(Mandatory=$true)][string]$RunDirectory,[Parameter(Mandatory=$true)][string]$Destination,[Parameter(Mandatory=$true)][string]$BatchIdentity,[Parameter(Mandatory=$true)][string]$RunIdentifier)
$ErrorActionPreference='Stop';$target='percentile';$result='nora_phase2w_percentile_tester_v3.csv';$required=@('compile.json','execution.json','compile.log','tester-journal.log','tester.htm',$result)
function Hash($p){(Get-FileHash $p -Algorithm SHA256).Hash.ToLowerInvariant()}
if(Test-Path $Destination){throw 'existing destination'};$tmp=$Destination+'.tmp-'+[guid]::NewGuid().ToString('N')
try {New-Item -ItemType Directory $tmp|Out-Null;foreach($name in $required){$in=Join-Path $RunDirectory $name;if(!(Test-Path $in -PathType Leaf)){throw "missing collected file: $name"};Copy-Item $in (Join-Path $tmp $name) -ErrorAction Stop};$files=Get-ChildItem $tmp -File|%{[ordered]@{relative_path=$_.Name;size=$_.Length;sha256=Hash $_.FullName}};$compile=Get-Content (Join-Path $tmp 'compile.json') -Raw|ConvertFrom-Json;$runtime=Get-Content (Join-Path $tmp 'execution.json') -Raw|ConvertFrom-Json;if(!$compile.compiler_success -or $compile.error_count -ne 0){throw 'compile evidence failed'};if($runtime.status -ne 'completed'){throw 'runtime incomplete'};$manifest=[ordered]@{schema_version='nora.phase2y.returned_package_v1';batch_identity=$BatchIdentity;run_identifier=$RunIdentifier;target_identifier=$target;compiler_record=$compile;runtime_record=$runtime;expected_result_filename=$result;actual_result_filename=$result;completion_marker_observed=($runtime.status -eq 'completed');failure_marker_observed=$false;interrupted=$false;timeout=$false;incomplete=$false;compiler_log_reference='compile.log';runtime_journal_reference='tester-journal.log';tester_report_reference='tester.htm';result_csv_reference=$result;csv_schema=@('row','source','percentile','pass');files=$files};$manifest.returned_package_semantic_identity=(ConvertTo-Json $manifest -Depth 12 -Compress|%{[Text.Encoding]::UTF8.GetBytes($_)}|%{[Security.Cryptography.SHA256]::HashData($_)}|%{[BitConverter]::ToString($_).Replace('-','').ToLowerInvariant()});$manifest|ConvertTo-Json -Depth 12|Set-Content (Join-Path $tmp 'returned_result_manifest.json') -Encoding utf8;Move-Item $tmp $Destination} catch {Remove-Item $tmp -Recurse -Force -ErrorAction SilentlyContinue;throw}
